#!/usr/bin/env python3
import json
import sys
import re
import os

def is_secrets_file(path: str) -> bool:
    """Check if this file is allowed to contain secrets."""
    basename = os.path.basename(path)
    allowed_secrets_files = {
        '.env', '.env.local', '.env.example', '.env.test',
        '.secrets', 'secrets.json', 'credentials.json',
        '.aws/credentials', '.aws/config',
        '*.pem', '*.key', '*.p8', '*.pfx', '*.jks'
    }
    for pattern in allowed_secrets_files:
        if pattern.startswith('*.'):
            if basename.endswith(pattern[1:]):
                return True
        elif basename == pattern or path.endswith('/' + pattern):
            return True
    return False

def contains_secret(content: str) -> tuple[bool, str]:
    """Check if content contains hardcoded secrets."""
    # Common secret patterns
    patterns = [
        (r'sk[-_]proj[-_][a-zA-Z0-9]{20,}', 'OpenAI API key'),
        (r'sk[-_][a-zA-Z0-9]{20,}', 'API key'),
        (r'pk[-_]live[-_][a-zA-Z0-9]{20,}', 'Stripe API key'),
        (r'AKIA[0-9A-Z]{16}', 'AWS Access Key'),
        (r'aws_secret_access_key\s*=\s*[^\s]+', 'AWS Secret Key'),
        (r'api[_-]?key\s*[=:]\s*[\'\"]?[a-zA-Z0-9_\-]{20,}[\'\"]?', 'API key assignment'),
        (r'password\s*[=:]\s*[\'\"]([^\'\"]){6,}[\'\"]', 'Password in plaintext'),
        (r'token\s*[=:]\s*[\'\"]([a-zA-Z0-9_\-\\.]{20,})[\'\"]', 'Token in plaintext'),
        (r'authorization\s*[=:]\s*Bearer\s+[a-zA-Z0-9_\-\\.]+', 'Bearer token'),
        (r'secret\s*[=:]\s*[\'\"]([^\'\"]){10,}[\'\"]', 'Secret value'),
        (r'private[_-]?key\s*[=:]\s*[\'\"]', 'Private key'),
        (r'BEGIN RSA PRIVATE KEY', 'RSA Private Key'),
        (r'BEGIN OPENSSH PRIVATE KEY', 'OpenSSH Private Key'),
    ]

    for pattern, secret_type in patterns:
        if re.search(pattern, content, re.IGNORECASE):
            return True, secret_type
    return False, ""

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only apply to Write and Edit tools
    if tool not in ("Write", "Edit"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path:
        return 0

    # Skip files that are allowed to contain secrets
    if is_secrets_file(file_path):
        return 0

    # Get the content being written
    new_string = inp.get("new_string", "")
    if not new_string:
        return 0

    # Check for secrets
    has_secret, secret_type = contains_secret(new_string)
    if has_secret:
        msg = (
            f"BLOCKED: Attempted to write {secret_type} to {file_path}\n"
            f"Secrets must come from environment variables (process.env, os.environ, etc.)\n"
            f"See CLAUDE.md: 'Secrets come from the environment. Never hardcode API keys, tokens, or passwords in source.'"
        )
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

