import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path or not file_path.endswith(".py"):
        return 0

    if not os.path.exists(file_path):
        return 0

    # Try pyflakes (detects undefined variables)
    try:
        result = subprocess.run(
            ["python", "-m", "pyflakes", file_path],
            capture_output=True,
            timeout=5,
            text=True
        )
        if result.stdout:
            print(f"REQUIRED FOLLOW-UP: Fix code issues detected:\n{result.stdout}", file=sys.stderr)
            return 2
    except (FileNotFoundError, subprocess.TimeoutExpired):
        # Fall back to py_compile
        try:
            subprocess.run(
                ["python", "-m", "py_compile", file_path],
                capture_output=True,
                check=True,
                timeout=5
            )
        except subprocess.CalledProcessError as e:
            error = e.stderr.decode() if e.stderr else (e.stdout.decode() if e.stdout else "Syntax error")
            print(f"REQUIRED FOLLOW-UP: Fix Python syntax errors:\n{error}", file=sys.stderr)
            return 2
        except Exception:
            pass
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
